// Class resource pools and named sub-choice catalogs, sourced from sw5e.com class pages,
// the Maneuvers list, and the shared Customization Options > Fighting Styles page.
//
// Engineer's Infuse Item modification catalogs (Armormech/Armstech/Gadgeteer/Artificer/Astrotech/
// Audiotech/Biochem/Biotech/Cybertech) are gated by ClassSubChoiceDef.archetypeName, since a
// character only has access to the modification list of their chosen Engineering Discipline.
// Unstable Engineering and Construction Engineering have no modification list of their own
// (their discipline features don't reference one) and Astrotech Engineering (Companion) reuses
// the Modification Slots table for Droid Companion feature uses rather than an item catalog, so
// none of the three are modeled here.

import type { ClassResourceDef, ClassSubChoiceDef, ClassSubChoiceOption } from "../types";

export const FIGHTING_STYLES: ClassSubChoiceOption[] = [
  { name: "Area Style", text: "When a creature successfully saves against your projector canister, you can use your bonus action to force them to repeat the save. When a creature rolls a 1 on the saving throw against a projector canister you control, they treat the effect's damage as if it had rolled the maximum." },
  { name: "Assisting Style", text: "You can take the Help action as a bonus action (or as a reaction on your turn if you already could). Creatures benefiting from your Help action can't have disadvantage on the affected ability check or attack roll." },
  { name: "Berserk Style", text: "When you hit with a melee weapon attack using Strength, you deal additional damage equal to your Strength modifier if that creature dealt damage to you since the start of your last turn. When you choose to let an attack that would miss you hit you instead, the creature rolls the damage as normal instead of choosing the maximum." },
  { name: "Blindfighting Style", text: "You gain blindsight out to 10 feet (or it increases by 10 feet if you already have it). You can use your bonus action to double the range of your blindsight until the start of your next turn." },
  { name: "Brawler Style", text: "You are proficient with improvised weapons. Your unarmed strike/natural weapon damage die increases by one step. When you attack, grapple, shove, or trip with an unarmed strike or one-handed weapon on your turn, you can use your bonus action to do the same again against the same creature." },
  { name: "Counterstrike Style", text: "When you would provoke an opportunity attack on your turn, you can use your bonus action to force the creature to make it if it can. Creatures who make opportunity attacks against you provoke opportunity attacks from you." },
  { name: "Covert Style", text: "You can take the Hide action as a bonus action (or as a reaction on your turn if you already could). Creatures you've damaged since the start of your last turn have disadvantage on Perception checks to find you." },
  { name: "Defense Style", text: "While wearing medium/heavy armor you're proficient with, mark a target within 30 feet with your bonus action; damage it deals to you is reduced by half your Strength or Constitution modifier while marked. You have advantage on Strength checks/saves to avoid being moved." },
  { name: "Disruption Style", text: "Choose force- or tech-casting. When a creature succeeds a concentration save you forced, you can force a reroll with your bonus action. Once per round, a hostile creature casting within 5 feet of you must first make a concentration-style save or waste the power." },
  { name: "Dual Wield Style", text: "You add your ability modifier to Two-Weapon Fighting damage rolls even if it wouldn't normally apply. You can draw or stow two weapons where you'd normally draw or stow only one." },
  { name: "Duelist Style", text: "Wielding one weapon and no others: feint with your bonus action (contested check for advantage on your next attack), or repeat a missed attack with your bonus action against the same target. Drawing/stowing that weapon no longer needs an object interaction once per turn." },
  { name: "Equilibrium Style", text: "While wearing light/no armor and no shield, mark a target within 30 feet with your bonus action; you gain a bonus to AC and Dex saves against effects it controls equal to half your Dexterity modifier while marked. You have advantage on Dexterity checks/saves to avoid being moved." },
  { name: "Explosives Style", text: "You can throw grenades and set mines with your bonus action (or reaction if already bonus action). When a creature rolls a 1 on a save against a grenade/mine/missile you control, they take maximum damage instead." },
  { name: "Formation Style", text: "You can take the Guard action as a bonus action (or reaction if already bonus action). You can bring a willing ally within 5 feet along when you move with your bonus action. Letting an attack meant for a guarded ally hit you instead rolls damage normally instead of maximum." },
  { name: "Formfighting Style", text: "Prerequisite: the ability to cast force powers. You learn three lightsaber forms. Once per turn you can draw or stow a lightweapon without an object interaction." },
  { name: "Great Weapon Style", text: "While wielding a two-handed light-/vibro-weapon you're proficient with, its damage rolls gain a minimum roll threshold. Grasping such a weapon with your other hand no longer needs an object interaction." },
  { name: "Guerrilla Style", text: "You can take the Disengage action as a bonus action (or reaction if already bonus action). When you Disengage, you ignore unenhanced difficult terrain and have advantage on the first check/save to avoid movement-impairing effects." },
  { name: "Gunning Style", text: "Creatures who roll a 1 on a save against your burst/rapid property take maximum damage instead. You can spray a line with the burst property, or double one set of rapid-property damage dice instead of adding them." },
  { name: "Mounted Style", text: "Mounting a vehicle or beast only uses 5 feet of movement. You can force an attack targeting your mount to target you instead, if you're a valid target." },
  { name: "Onslaught Style", text: "You can take the Dash action as a bonus action (or reaction if already bonus action). You can make a melee attack roll against a creature's AC instead of a contested check to shove or trip it (with advantage if wielding your weapon two-handed)." },
  { name: "Poisoner Style", text: "You can apply poisons with your bonus action (or reaction if already bonus action). Creatures who roll a 1 on a save against a poison you control take maximum damage instead." },
  { name: "Secured Style", text: "You can treat a fixed weapon as a light shield until the start of your next turn (forgoing attacks with it for the duration). You can benefit from fixed weapons while the hand is full." },
  { name: "Sentinel Style", text: "Creatures provoke an opportunity attack when they move within your reach or move 5+ feet within it. Hitting a creature no more than one size larger with an opportunity attack gives it 4 slowed levels until the end of the turn." },
  { name: "Sharpshooter Style", text: "You can mark a target more than 30 feet away with your bonus action; if it moves 5+ feet before your next turn, it provokes a ranged opportunity attack from you. Your ranged attacks reduce partial cover by one step against targets past 30 feet. Grasping a two-handed weapon one-handed no longer needs an object interaction." },
  { name: "Shield Style", text: "You're no longer restricted to light weapons while wielding a heavy shield. You can shove or trip with your shield as a bonus action. Using a shield as an improvised weapon, you're considered proficient and it gains the light/fixed (light shield) or heavy (heavy shield) property." },
  { name: "Snapshot Style", text: "No disadvantage on ranged attacks from being within 5 feet of a hostile creature. Your ranged attacks reduce partial cover by one step against targets within 30 feet. Your blaster damage against targets within 30 feet gains a minimum roll threshold. Grasping a two-handed weapon one-handed no longer needs an object interaction." },
  { name: "Split Style", text: "You add your ability modifier to Double-Weapon Fighting attack rolls and Two-Weapon Fighting damage rolls even if it wouldn't normally apply." },
  { name: "Spotting Style", text: "You can take the Search action as a bonus action (or reaction if already bonus action). Advantage on checks/saves to determine the nature of illusions (or reroll one die if you'd already have advantage)." },
  { name: "Superiority Style", text: "You learn one maneuver and gain one superiority die (d4, growing to d6 at 5th, d8 at 9th, d10 at 13th, d12 at 17th), regained on a short or long rest." },
  { name: "Throwing Style", text: "After a ranged thrown-weapon attack, you can immediately draw another weapon and move up to 5 feet without provoking opportunity attacks. On a miss with a thrown weapon, you can use your bonus action to repeat the attack against a creature within 15 feet behind your target." },
  { name: "Twin-Blade Style", text: "You add your ability modifier to Double-Weapon Fighting attack rolls even if it wouldn't normally apply. Grasping a double weapon one-handed no longer needs an object interaction." },
  { name: "Versatile Style", text: "On a miss with a versatile weapon wielded in two hands, repeat the attack one-handed with your bonus action. Wielded one-handed instead, attempt to shove or trip with your bonus action. Grasping such a weapon one-handed no longer needs an object interaction." },
];

// Fighting Masteries, referenced by the Fighting Master feat and the Fighter Strategist
// "Mastery Strategist" pick (that nested pick is left as descriptive text, consistent with
// the rest of the archetype/class sub-choice nesting scope-cuts).
export const FIGHTING_MASTERIES: ClassSubChoiceOption[] = [
  { name: "Area Mastery", text: "Your projector canister save DC can use 8 + proficiency bonus + Intelligence modifier if higher. Your projector canisters reduce partial cover by one step (ignoring one-quarter cover entirely). You can trade proficiency bonus from a projector canister's save DC for the same bonus to its damage." },
  { name: "Assisting Mastery", text: "Helping an ally at the cost of up to half your speed lets them reroll one die of their advantage. Helping against an enemy the same way gives allies attacking it the same reroll. Your Help action's range becomes 5 feet per proficiency bonus." },
  { name: "Berserk Mastery", text: "After being critically hit, advantage on your next attack against that creature. Advantage on saves against being forced to act against your will, frightened, or prevented from attacking. Reaction melee/unarmed counter-strike (+proficiency bonus damage) when hit by an adjacent creature." },
  { name: "Blindfighting Mastery", text: "Attackers who'd have disadvantage against you from your blindness must reroll one die. Your own advantage from a target's blindness lets you reroll one die. Blindsight increases by 5 feet per proficiency bonus." },
  { name: "Brawler Mastery", text: "Improvised weapons deal 1d6 and gain versatile (2d4). Unarmed/natural weapon damage die increases one step. Speed isn't halved carrying a same-size-or-smaller grappled creature. Once per turn, a bonus unarmed strike without proficiency bonus after a one-handed hit." },
  { name: "Counterstrike Mastery", text: "Opportunity attacks against you have disadvantage on damage; your opportunity attacks that hit have advantage on damage. Advantage on damage-reduction die rolls. Once per round, gain a special reaction for an opportunity attack (without proficiency bonus). Reaction opportunity attack (without proficiency bonus, imposing disadvantage) when targeted by a weapon attack." },
  { name: "Covert Mastery", text: "You can hide while only lightly obscured. Dim light doesn't impose disadvantage on sight-based Perception. Missing with an attack while hidden doesn't reveal you. Once per turn, extra damage (+proficiency bonus) while hidden." },
  { name: "Defense Mastery", text: "In proficient medium/heavy armor, react to a melee attack (hit or miss) by shoving the attacker 10 feet. Don/doff armor time halved. Weapon damage reduced by proficiency bonus (minimum 1) while in proficient medium/heavy armor." },
  { name: "Disruption Mastery", text: "Choose force- or tech-casting. Nearby casters of that type provoke an opportunity attack when casting. Advantage on saves against powers from creatures you've damaged since your last turn. Concentration DCs you force increase by your proficiency bonus." },
  { name: "Dual Wield Mastery", text: "Two-Weapon Fighting works even without the light property. Reload two weapons at once, no free hand needed. Once per round, opportunity attack with both weapons. Forgo Two-Weapon Fighting attacks for +1 AC each; or forgo proficiency bonus for an extra attack." },
  { name: "Duelist Mastery", text: "Advantage on checks/saves to avoid being disarmed. Single-weapon Attack action can trade proficiency bonus for a bonus reaction attack (also without proficiency bonus). Single-weapon reaction adds proficiency bonus to AC against one melee hit." },
  { name: "Equilibrium Mastery", text: "Reaction to catch a weapon you're disarmed of. In light/no armor, no shield: react to a miss with a counter-attack (no proficiency bonus), or react to a hit by imposing a proficiency-bonus penalty on the attack roll." },
  { name: "Explosives Mastery", text: "Grenade/mine/missile save DC can use 8 + proficiency bonus + Intelligence modifier if higher. Advantage on saves against your own such items. Trade proficiency bonus from the save DC for the same bonus to damage." },
  { name: "Formation Mastery", text: "Guarded allies have advantage on Dexterity saves affecting only them. React to a miss against an adjacent ally with a counter-attack (no proficiency bonus), or react to a hit against them by imposing a proficiency-bonus penalty on the attack roll." },
  { name: "Formfighting Mastery", text: "Learn three lightsaber forms (seven if you already know three). Once per turn, forgo proficiency bonus to use a lightsaber form without your bonus action. Once per turn, forgo proficiency bonus so a hit also deals weapon damage (2x proficiency bonus) to an adjacent second creature.", prerequisite: "The ability to cast force powers" },
  { name: "Great Weapon Mastery", text: "Bonus-action melee attack after a crit or a kill. Two-handed light-/vibro-weapon: repeat a miss with your bonus action for extra kinetic damage (Strength modifier). Advantage on saves/checks against disarm. Forgo proficiency bonus for +2x proficiency bonus damage with such weapons." },
  { name: "Guerrilla Mastery", text: "Move through hostile creatures' spaces regardless of size. Opportunity-attack hits let you move half speed without provoking. React to an adjacent enemy with Disengage + half speed move. Once per turn, extra damage (2x proficiency bonus) when a flanking ally is present." },
  { name: "Gunning Mastery", text: "Creatures who succeed a burst/rapid save still take damage equal to the weapon's ability modifier. Treat weapon Strength requirements one step lower. Forgo proficiency bonus on burst/rapid save DC for extra damage to those who fail." },
  { name: "Mounted Mastery", text: "React to your mount's half-damage Dexterity save for no damage instead. Mounted beast bonus-action attack (or reaction if already bonus action). Mounted vehicle action as bonus action (or reaction). Once per turn, advantage plus proficiency bonus damage against a smaller unmounted creature." },
  { name: "Onslaught Mastery", text: "Creatures falling prone near you provoke an opportunity attack. Reroll a die when you'd have advantage from a prone target. Standing up near you provokes an opportunity attack. Once per turn, +proficiency bonus damage after a 10-foot charge into a melee hit." },
  { name: "Poisoner Mastery", text: "Poison save DC can use 8 + proficiency bonus + Intelligence modifier if higher. Poisons affect an extra hit/ammo. Poisoned creatures have disadvantage on saves against your poisons. Trade proficiency bonus from the save DC for 2x proficiency bonus damage." },
  { name: "Secured Mastery", text: "Wield full Strength modifier worth of forearm items instead of half. Reload fixed weapons with reaction or object interaction (or free once per turn). Once per turn, bonus fixed-weapon attack (no proficiency bonus) after a non-fixed miss. Once per turn, forgo a fixed-weapon attack for +proficiency bonus AC." },
  { name: "Sentinel Mastery", text: "Creatures in your reach provoke opportunity attacks even when Disengaging. Dodge action grants a second reaction once per round. Bonus action defensive stance grants special reactions (equal to proficiency bonus) usable only for opportunity attacks." },
  { name: "Sharpshooter Mastery", text: "No disadvantage at long range. Ranged attacks past 30 feet reduce partial cover one step (ignoring one-quarter entirely). Forgo proficiency bonus on a proficient blaster attack past 30 feet for +2x proficiency bonus damage on a hit." },
  { name: "Shield Mastery", text: "Add your shield's AC bonus to Dexterity saves. Proficient shield: succeeding a half-damage Dexterity save can react to take none instead. Proficient shield: reaction to reduce damage taken by your proficiency bonus." },
  { name: "Snapshot Mastery", text: "Ranged attacks within 30 feet reduce partial cover one step (ignoring one-quarter entirely). Creatures moving within 30 feet provoke a ranged opportunity attack. Proficient blaster Attack action within 30 feet: forgo proficiency bonus for a bonus-action extra attack, also without proficiency bonus." },
  { name: "Split Mastery", text: "Detaching/reattaching an interlocking weapon is free once per turn. Double-/Two-Weapon Fighting works without the light property. Forgo proficiency bonus on a dual-wielded melee hit for +proficiency bonus damage. Forgo proficiency bonus on a Double-Weapon Fighting bonus attack for an extra attack, also without proficiency bonus." },
  { name: "Spotting Mastery", text: "No disadvantage from light obscurement within 120 feet for Perception. Redirected attacks against your illusory duplicate roll with disadvantage. Searching gives no tell. Found hidden creatures have disadvantage hiding from you again until your next turn. Advantage on checks/attacks/saves during a Search within 5 feet per proficiency bonus." },
  { name: "Superiority Mastery", text: "Learn one maneuver (three if you already know one). Gain one superiority die (two more if you already have one), scaling die size with level. Bonus action for advantage on a superiority die roll. Choose one known maneuver usable with a flat d4 instead of a superiority die, proficiency-bonus times per long rest." },
  { name: "Throwing Mastery", text: "No disadvantage at long range with thrown weapons. Hitting with a thrown ranged attack grants advantage on your next melee attack against that creature. Draw a thrown weapon free once per turn. Once per turn, thrown ranged attack in normal range without proficiency bonus, no action required." },
  { name: "Twin-Blade Mastery", text: "Maximum damage die grants +1 to your next attack against that creature. Double-Weapon Fighting works without the light property. Forgo proficiency bonus wielding a double weapon two-handed for +1.5x proficiency bonus damage, or one-handed for +proficiency bonus damage." },
  { name: "Versatile Mastery", text: "Once per turn two-handed melee hit can push the target 5 feet (Strength save) and let you follow. Once per turn one-handed melee hit against a shield-user negates their shield AC for that attack. Forgo proficiency bonus with a versatile weapon two-handed for +1.5x proficiency bonus damage, or one-handed for +proficiency bonus damage." },
];

