export const SPLASHCLASS_IMPROVEMENTS: ClassSubChoiceOption[] = [
  { name: "Berserker", text: "On your turn, you can enter a rage as a bonus action if you aren't wearing heavy armor. While raging: advantage on Strength checks/saves; +2 damage on Strength melee attacks; resistance to kinetic and energy damage. Can't cast or concentrate on powers while raging. Lasts 1 minute. Usable once, plus an additional use at 11th level; regain all uses on a long rest.", prerequisite: "No levels in berserker" },
  { name: "Consular", text: "You gain one Force-Empowered Casting option of your choice from those available to the consular class (an additional option at 11th level), letting you expend force points to modify a power you cast. You can spend a number of force points this way equal to your proficiency bonus, regained on a long rest.", prerequisite: "No levels in consular, the ability to cast force powers" },
  { name: "Engineer", text: "As a bonus action, choose a creature other than yourself within 60 feet who can hear you; it gains one Potent Aptitude die (a d4) it can add to one ability check, attack roll, or saving throw within 10 minutes. Usable a number of times equal to your proficiency bonus, regained on a long rest.", prerequisite: "No levels in engineer" },
  { name: "Fighter", text: "You learn one maneuver of your choice from those available to the fighter class (an additional maneuver at 11th level), fueled by superiority dice equal to your proficiency bonus (d4s), regained on a long rest.", prerequisite: "No levels in fighter" },
  { name: "Guardian", text: "When you hit with a melee weapon attack, you can expend force points to deal additional damage of the weapon's damage type: 1d8 per point spent, up to 2d8 per hit. You can spend a number of force points this way equal to your proficiency bonus, regained on a long rest.", prerequisite: "No levels in guardian, the ability to cast force powers" },
  { name: "Monk", text: "You can make an unarmed strike, take the Disengage action, or take the Dash action as a bonus action (stacking with an existing bonus-action unarmed strike/Disengage/Dash by granting an additional Dodge or doubled jump distance). Usable a combined number of times equal to your proficiency bonus, regained on a long rest.", prerequisite: "No levels in monk" },
  { name: "Operative", text: "Once per turn, deal an extra 1d6 damage (matching the weapon's damage type) to a creature you hit with a finesse or ranged weapon attack while you have advantage on the attack roll (or, without advantage, if another non-incapacitated enemy of the target is within 5 feet and you don't have disadvantage). Usable a number of times equal to your proficiency bonus, regained on a long rest.", prerequisite: "No levels in operative" },
  { name: "Scholar", text: "As a bonus action, analyze a target you can see within 60 feet. For the next minute: against a hostile target, your finesse/blaster attack and damage rolls may use Intelligence instead of Strength/Dexterity; a friendly target can end the effect to add your Intelligence modifier to one attack roll, ability check, or saving throw (once per short/long rest). Usable a number of times equal to half your proficiency bonus (rounded up), regained on a long rest.", prerequisite: "No levels in scholar" },
  { name: "Scout", text: "Once on each of your turns, mark a creature you can see within 120 feet as your quarry (no action required) for the next hour: once per turn, deal 1d4 additional damage of the weapon's type on a hit; advantage on Wisdom (Perception)/(Survival) checks to find it on the same planet. Only one quarry at a time; usable a number of times equal to half your proficiency bonus (rounded up), regained on a long rest.", prerequisite: "No levels in scout" },
  { name: "Sentinel", text: "When you hit with a melee weapon attack, spend 1 force point to use a Force-Empowered Self effect (once each per turn, one per hit): Deflection (roll a d4, add to AC against one attack before your next turn); Double Strike (roll a d4, deal that much additional damage of the same type); Slow Time (roll a d4, increase speed by 5x the amount until end of turn). You can spend a number of force points this way equal to your proficiency bonus, regained on a long rest.", prerequisite: "No levels in sentinel, the ability to cast force powers" },
];

// Engineer "Infuse Item" modification lists, one per Engineering Discipline archetype.
// Each discipline's modified item (Modified Armor, Modified Weaponry, etc.) has a slot count
// that grows per the shared "Modification Slots" column of the engineer class table.
const ENGINEER_MOD_SLOTS_BY_LEVEL = [0, 0, 4, 4, 5, 5, 5, 5, 6, 6, 7, 7, 8, 8, 8, 8, 9, 9, 9, 9];

export const ARMORMECH_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Absorption Shield","text":"You modify your physical shield to block incoming damage. As a bonus action you can activate this ability and gain temporary hit points equal to 1d4 + Intelligence modifier, which last for one hour.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain any expended uses when you finish a long rest.","prerequisite":"Physical Shield"},{"name":"Accelerated Movement","text":"You reduce the weight of your modified armor's bulk and increase the power to joints. If the armor has a Strength requirement, you ignore it. The modified armor's weight is reduced by 15 lbs. While wearing your modified armor your speed increases by 10 feet. This applies to all movement speeds you have while wearing your armor.","prerequisite":"Armor"},{"name":"Adaptable Armor","text":"You integrate deployable hooks and fins into your armor, augmenting its mobility. While wearing your modified armor, you gain a climbing speed equal to your walking speed, and you can move up, down, and across vertical surfaces and upside down along ceilings, while leaving your hands free. Additionally, you gain a swim speed equal to your walking speed.","prerequisite":"Armor"},{"name":"Advanced Power Fist","text":"You further modify your modified armor's gauntlet with increased reinforcement and weight. Your modified armor's unarmed strike deals 1d8 kinetic damage. Additionally, your critical hit range with your unarmed strikes increases by 1.","prerequisite":"11th level, Prototype Power Fist"},{"name":"Artificially Intelligent","text":"You install an artificial intelligence into your modified armor. While wearing your modified armor, when you make an ability check, your armor's artificial intelligence can take the Help action.\n\nYou can use this feature four times. You gain an additional use at 13th and 17th level. You regain all expended uses when you complete a long rest.","prerequisite":"9th level, Armor"},{"name":"Bonded Plates","text":"You gain a +1 bonus to AC against melee attacks. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Collapsible Suit","text":"Your modified armor can collapse into a case for easy storage. When transformed this way the armor is indistinguishable from a normal case and weighs one-\n\nthird its normal weight. As an action you can don or doff the armor, allowing it to transform as needed.","prerequisite":"5th level, Armor"},{"name":"Darkvision Visor","text":"While wearing your modified armor, you have darkvision to a range of 60 feet. If you already have darkvision, this modification increases its range by 30 feet.","prerequisite":"Armor"},{"name":"Enhanced Endurance","text":"When you are reduced to 0 hit points while wearing your modified armor but not killed outright, you can drop to 1 hit point instead. You can't use this feature again until you finish a long rest.","prerequisite":"Armor"},{"name":"Electroshock Shield","text":"You install electroshockers in your shield generator. Whenever an enemy misses you with a melee attack, you can use your reaction to do 1d4 + your Intelligence modifier lightning damage to the attacker.","prerequisite":"Shield Generator"},{"name":"Flight","text":"You integrate a propulsion system into your modified armor. While wearing your modified armor you have an enhanced flying speed of 30 feet.","prerequisite":"9th level, Armor"},{"name":"Grappling Harpoon","text":"Your modified armor gains an integrated grappling harpoon set into your gauntlet. With this harpoon, you can make a ranged weapon attack with a range of 30/60. On a hit, it deals 1d6 kinetic damage. This attack can target a surface, object, or creature.\n\nA creature struck by this attack is impaled by the harpoon. As an action, a creature can attempt to remove the harpoon. Removing the harpoon requires a Strength check. While the harpoon is stuck in the target, you are connected to the target by a 60 foot cable.\n\nWhile the harpoon is deployed, you can use your bonus action to activate the reel, pulling yourself to the location if the target is larger than you. A creature or object your size or smaller is pulled to you. Alternatively, you can opt to release the cable (no action required).\n\nOnce you've used this feature, you can't use it again until you recover and reinsert the harpoon as an action.","prerequisite":"Armor"},{"name":"Heavy Suit","text":"You enhance your suit, making it difficult to move. As a bonus action, you can anchor or deanchor your feet to the ground. While anchored, your speed is 0, you have advantage on Strength checks and Strength saving throws, and your carrying capacity and the weight you can push, drag, or lift doubles. If it would already double, it instead triples.","prerequisite":"5th level, Armor"},{"name":"Infiltration Suit","text":"You install a cloaking device in your modified armor. This device has 2 charges. As an action you can use 1 charge to cast _infiltrate_ targeting yourself.\n\nThe cloaking device regains all expended charges after a long rest.","prerequisite":"Armor"},{"name":"Magnetized Shield","text":"You modify your physical shield such that when a melee weapon attack misses you by an amount less than or equal to your bonus to AC from your shield, the attacking creature must make a Strength check against your tech save DC. On a failed save, the creature's weapon adheres to the shield. As an action, a creature can repeat this check. On a success, the weapon is freed.","prerequisite":"Physical Shield"},{"name":"Overload Shield","text":"You modify your shield generator to overload. As an action you can overload your shield. Each Large or smaller creature within 5 feet of you must make a Dexterity or Strength saving throw (their choice). On a failed save, they are pushed back 5 feet and knocked prone.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain any expended uses when you finish a long rest.","prerequisite":"Shield Generator"},{"name":"Power Fist","text":"You modify your modified armor gauntlet with increased reinforcement and weight. Your modified armor's unarmed strike deals 1d4 kinetic damage.\n\nAdditionally, when you take the Attack action and make an unarmed strike, you can make an additional unarmed strike as a bonus action.","prerequisite":"Armor"},{"name":"Prototype Power Fist","text":"You further modify your modified armor gauntlet with increased reinforcement and weight. Your modified armor's unarmed strike deals 1d6 kinetic damage and has the following property.\n\nIf you or your target move at least 10 feet in a straight line immediately before making an unarmed strike, the first unarmed strike you make deals additional damage equal to your Intelligence modifier.","prerequisite":"5th level, Power Fist"},{"name":"Reinforced Underlay","text":"You gain a +1 bonus to AC against ranged attacks. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Resistance","text":"You tune your modified armor against certain forms of damage. Choose acid, cold, fire, ion, lightning, or sonic damage. While wearing your modified armor you have resistance to that type of damage.\n\nYou can select this modification multiple times. Each time you do so, you must choose a different damage type.","prerequisite":"Armor"},{"name":"Sealed Suit","text":"As a bonus action you can hermetically seal your modified armor, giving you an air supply for up to 1 hour and making you immune to poison (but not curing you of existing poisoned conditions). Your armor regains 1 minute of air for every minute that you are not submerged and the armor is not sealed.\n\nAdditionally, while you are wearing your modified armor you are considered adapted to cold and hot climates as well as high altitude, as described in chapter 5 of the Dungeon Master's Guide.","prerequisite":"5th level, Armor"},{"name":"Sentient Armor","text":"Your artificial intelligence has learned to control the suit without you being in it. It is now a valid target of the _tracker droid interface_ tech power.\n\nWhile your armor is acting independently, it uses your ability scores, saving throws, and skills, and it has hit points equal to your engineer level. If reduced to 0 hit points, it falls directly to the ground, and it can not be equipped again until you finish a long rest.","prerequisite":"13th level, Artificially Intelligent"},{"name":"Shield Amplifier","text":"You modify your shield generator to project outward. As a bonus action you can amplify your shield until the start of your next turn. Each creature within 5 feet of you gains a bonus to AC equal to your shield's bonus.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain any expended uses when you finish a long rest.","prerequisite":"Shield Generator"},{"name":"Shield Anchor","text":"You modify your shield to be used as a portable source of cover. As an action, you can anchor or deanchor the shield. While anchored, you gain no benefit from a shield, and it does not require the use of a hand. Instead, while anchored, a light shield provides one-quarter cover, a medium shield provides half cover, and a heavy shield provides three-quarters cover.","prerequisite":"Physical Shield"},{"name":"Tech Blast","text":"You modify your modified armor gauntlet with a blaster weapon with which you are proficient. The weapon uses your Intelligence modifier for its attack and damage rolls, and deals 1d8 energy damage on a hit. It has a normal range of 30 feet and a long range of 120 feet.","prerequisite":"Armor"},{"name":"Weapon Integration Armoring","text":"You can integrate a single weapon that weighs no more than 8 lb. into your armor. While integrated, that weapon gains the hidden property. Additionally, you have advantage on Strength saving throws to avoid being disarmed.","prerequisite":"Armor"}];

export const ARMSTECH_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Accuracy Focus","text":"You gain a +1 bonus to attack rolls made with this weapon. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level, Blaster"},{"name":"Amplifying Barrel","text":"You gain a +1 bonus to damage rolls made with this weapon. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level, Blaster"},{"name":"Bayonet","text":"You affix a short blade to the barrel of your modified blaster weapon, allowing you to make a melee weapon attack with it. The blade is a vibroweapon weapon with the finesse property that you are proficient with, and deals 1d6 kinetic damage.","prerequisite":"Blaster"},{"name":"Burst Core","text":"Your weapon gains the burst property, with a burst number equal to its reload number.","prerequisite":"Blaster"},{"name":"Booming Strikes","text":"You pack extra power into your modified weapon. Once per turn, when you hit with the weapon, you can deal an additional 1d6 damage. If you do so, the weapon makes a loud boom which can be heard 100 feet away. If you are hidden, Intelligence (Investigation) and Wisdom (Perception) checks made to locate you that rely on sound have advantage.","prerequisite":"5th level"},{"name":"Celerity Oscillator","text":"Once per turn, when you deal damage with your modified weapon, your walking speed increases by 10 feet until the start of your next turn, and the damaged creature can't make opportunity attacks against you for the rest of your turn."},{"name":"Collapsible Frame","text":"You install an expandable hilt on your modified weapon. Your modified weapon gains the reach property.","prerequisite":"Vibroweapon"},{"name":"Compensation Oscillator","text":"You install a compensation oscillator in your modified vibroweapon, removing the dexterity property from it.","prerequisite":"Vibroweapon with the dexterity property"},{"name":"Contoured Grip","text":"You gain a +1 bonus to attack rolls made with this weapon. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level, Vibroweapon"},{"name":"Expanded Magazine","text":"Your modified weapon can be more efficiently reloaded. You can reload your modified weapon once without using an action. You can't use this feature again until you reload the weapon with an action.","prerequisite":"Blaster"},{"name":"Flashlight","text":"You affix a targeted light to your weapon. As a bonus action, you can toggle the light on or off. While on, your weapon sheds bright light in a 60-foot cone."},{"name":"Harpoon Reel","text":"You install a secondary firemode that launches a harpoon attached to a tightly coiled cord. With this harpoon, you can make a ranged weapon attack with a range of 30/60. On a hit, it deals 1d6 kinetic damage. This attack can target a surface, object, or creature.\n\nA creature struck by this attack is impaled by the harpoon. As an action, a creature can attempt to remove the harpoon. Removing the harpoon requires a Strength check. While the harpoon is stuck in the target, you are connected to the target by a 60 foot cable.\n\nWhile connected in this manner, you can use your bonus action to activate the reel, pulling yourself to the location if the target is your size or larger. A creature or object smaller than you is pulled to you. Alternatively, you can opt to release the cable (no action required).\n\nOnce you've used this feature, you can't use it again until you recover and reinsert the harpoon as an action."},{"name":"Imbue Weapon","text":"You modify your weapon to carry a charge. Over the course of a short rest, you can cast an at-will tech power, channeling it into your weapon. The next time you hit with your weapon, the stored power is released. If the power would require an attack roll, make a tech attack roll. If the power would require a saving throw, the target must make the saving throw as normal. On a hit, or a failure, the target suffers the power's normal effects.","prerequisite":"9th level"},{"name":"Improved Burst Core","text":"Your weapon's burst number is reduced to half its reload number.","prerequisite":"9th level, Burst Core"},{"name":"Integrated Magazine","text":"Your modified weapon can be more efficiently reloaded. You can reload your modified weapon twice without using an action. You can't use this feature again until you reload the weapon with an action.","prerequisite":"Expanded Magazine"},{"name":"Jagged Oscillator","text":"When you critically hit with the weapon, you deal an additional 1d8 kinetic damage.","prerequisite":"Vibroweapon"},{"name":"Keen Oscillator","text":"Your weapon's critical hit range increases by 1.","prerequisite":"5th level, Jagged Oscillator"},{"name":"Neutronium Edge","text":"You gain a +1 bonus to damage rolls made with this weapon. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level, Vibroweapon"},{"name":"Overcharge Weapon","text":"You gain the ability to channel your tech power to enhance your weapon's damage. You can expend one tech slot to deal additional damage to the target. The extra damage is 1d6 for a 1st-level tech slot, plus 1d6 for each slot level higher than 1st, to a maximum of 5d6. The damage is the same type as the weapon damage. If you also use your Booming Strikes with an attack, you add this damage to the extra damage of your Booming Strikes.","prerequisite":"11th level, Booming Strikes"},{"name":"Power Loop","text":"When you hit with the weapon, you can choose to channel the energy generated, gaining temporary hit points equal to half the damage dealt.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"9th level"},{"name":"Recoil Dampener","text":"You install a recoil dampener in your modified blaster, removing the strength property from it.","prerequisite":"Blaster with the strength property"},{"name":"Returning Weapon Guard","text":"You install a retractible chain in your modified vibroweapon. If the weapon does not already have the thrown property, it gains it with a range of 20/60. Additionally, it gains the returning property.","prerequisite":"Vibroweapon"},{"name":"Screening Weapon","text":"You modify your modified weapon with a sound dampening module. When you make a weapon attack with your weapon while hidden, Investigation and Perception checks made to locate you that rely on sound have disadvantage."},{"name":"Shock Absorber","text":"You add a reclamation device to your modified weapon to gather energy from the surroundings when it is present. While wielding your modified weapon, you can cast the _absorb energy_ tech power and the power's extra damage applies to both melee and ranged weapon attacks."},{"name":"Siege Weapon","text":"You modify your weapon to be more effective against barriers. Your weapon deals double damage against structures."},{"name":"Shocking Harpoon","text":"After hitting a creature with the harpoon fire mode, you can use the connection to deliver an at-will tech power. As a bonus action, you can cast an at-will tech power at the target with a range of touch. If the power\n\nrequires an attack roll, you have advantage. If the target requires a saving throw, the target has disadvantage.\n\nOnce you've used this feature, you can't use it again until you recover the harpoon.","prerequisite":"9th level, Harpoon Reel"},{"name":"Shocking Oscillator","text":"When you hit with the weapon, you can create an electronic burst. Each creature in a 15-foot cone centered on the creature you hit must make a Dexterity saving throw, taking 1d8 lightning damage on a failed save or half as much on a successful one.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"9th level, Vibroweapon"},{"name":"Snap Fire","text":"You modify your modified blaster weapon for quick shots. You can use your reaction to take a opportunity attack with your modified weapon if an enemy comes within 10 feet of you. You have disadvantage on this attack.","prerequisite":"9th level, Blaster"},{"name":"Staggering Oscillator","text":"When you hit with the weapon, you can force the target to make a Strength saving throw. On a failed save, the creature is pushed back 10 feet and knocked prone.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"Vibroweapon"},{"name":"Tracker","text":"You add a tracking mechanism to your modified weapon. The tracker has 3 charges. As a bonus action you can use 1 charge to cast _target lock_. As an action you can use 2 charges to cast _detect invisibility_.\n\nThe tracker regains all expended charges after a long rest.","prerequisite":"5th level"},{"name":"Truelight","text":"You modify your flashlight with a toggle allowing you to briefly gain enhanced sight. As a bonus action, you can activate the truesight feature of your flashlight. When toggled on, for the next minute your flashlight now automatically dispel illusions and can detect invisibility, as with truesight.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"11th level, Flashlight"},{"name":"Venomous Oscillator","text":"As a bonus action, you can coat your weapon in a thin layer of poison for 1 minute. The next time you hit with the weapon, the creature must make a Constitution saving throw against your tech save DC. On a failed save, a creature takes 1d10 poison damage and becomes poisoned for 1 minute.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"9th level, Vibroweapon"}];

export const GADGETEER_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Advanced Grounding System","text":"While wearing your gadgeteer harness you have immunity to lightning damage.","prerequisite":"13th level, Prototype Grounding System"},{"name":"Auto-Injection Regenerator","text":"You install a special kolto injector into your gadgeteer harness that can inject you with kolto in response to pain. When you take damage, you can use your reaction and expend a Hit Die to regain health as long as the damage would not reduce your hit points to 0.","prerequisite":"5th level"},{"name":"Autothrusters","text":"You can take the Dash and Disengage actions as a bonus action while your jet pack is active.","prerequisite":"Jet Pack"},{"name":"Climbing Gloves","text":"You craft a set of gloves with a powerful assisted grip. While wearing these gloves, you have a climbing speed of 20 feet, and you have advantage on Strength saving throws and Strength (Athletics) checks that involve climbing."},{"name":"Darkvision Goggles","text":"You craft a pair of sight-enhancing goggles. While wearing these goggles, you have darkvision to a range of 60 feet. If you already have darkvision, this modification increases its range by 30 feet."},{"name":"Extended Tank","text":"Your jet pack now lasts up to 10 minutes when activated.","prerequisite":"5th level, Jet Pack"},{"name":"Flame Vents","text":"You learn the *flame sweep* tech power and can cast it at first level without using tech points. Once you have used this ability, you cannot use it again until you finish a short or long rest.\n\nAdditionally, while your jet pack is active, you can cast *flame sweep* using your bonus action instead of your action.","prerequisite":"9th level, Jet Pack"},{"name":"Frailcasting Inhibitor","text":"You gain a +1 bonus to the tech save DC of powers you cast that requires a Strength or Constitution saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Grounding System","text":"While wearing your gadgeteer harness you are immune to the shocked condition."},{"name":"Integrated Amplifier","text":"You gain a +1 bonus to melee tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Integrated Rangefinder","text":"You gain a +1 bonus to ranged tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Intelligence Core Override","text":"You can cast the *override interface* tech power at 5th level without spending tech points.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"9th level"},{"name":"Jet Pack","text":"You integrate a jet pack into your gadgeteer harness to grant you temporary, limited flight. Activating or deactivating the jets requires a bonus action and, while active, you have a flying speed of 30 feet.\n\nThe jet pack last for 1 minute before deactivating. Once the jets have been activated, they can't be activated again until you finish a short or long rest.\n\nYour jet pack's speed increases to 40 feet at 5th level, 50 feet at 9th level, 60 feet at 13th level, 70 feet at 17th level, and 80 feet at 20th level."},{"name":"Mechanical Arm","text":"You create a mechanical arm which mounts to your shoulder, which you can use independently. You can only gain the benefit of items held by two of your arms at any given time.\n\nYou can choose this modification twice."},{"name":"Mimicker","text":"You create a device that attaches to your gadgeteer harness. Your mimicker casts a shadow that makes you appear to be standing in a place near your actual location, causing any creature to have disadvantage on attack rolls against you. If you take damage, the property ceases to function for 1 minute. Your mimicker is suppressed while you are incapacitated, restrained, or otherwise unable to move.","prerequisite":"9th level"},{"name":"Miniaturized Hydraulics","text":"Your gadgeteer harness can store 20 pounds of equipment without adding to your encumbrance."},{"name":"Oil Spill","text":"As an action, you can cast the *oil slick* tech power without expending tech points. When you cast the power in this way, the oil will remain in place for the full duration of the power.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again."},{"name":"Powered Grappling Hook","text":"While your wrist-mounted grappling hook is deployed, when you cast a tech power with a range of touch, your hook can deliver the power as if it had cast it.","prerequisite":"9th level, Wrist-Mounted Grappling Hook"},{"name":"Prototype Grounding System","text":"While wearing your gadgeteer harness you have resistance to lightning damage.","prerequisite":"9th level, Grounding System"},{"name":"Rendcasting Inhibitor","text":"You gain a +1 bonus to the tech save DC of powers you cast that requires a Dexterity or Intelligence saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Quick Start Engine","text":"You can now activate your Jet Pack as an object interaction rather than as a bonus action.","prerequisite":"5th level, Jet Pack"},{"name":"Recycled Adrenals","text":"You can augment a single adrenal to regain its charge. This adrenal can only be used by you, and it can only affect you. Once you've used this adrenal, you can't use it again until you finish a long rest."},{"name":"Recycled Explosives","text":"You can augment a single explosive to regain its charge. This explosive can only be used by you, and it uses your tech save DC instead of its own, unless its own DC would be higher. Once you've used this explosive, you can't use it again until you finish a long rest."},{"name":"Recycled Stimpacs","text":"You can augment a single stimpac to regain its charge. This stimpac can only be used by you, and it can only affect you. Once you've used this stimpac, you can't use it again until you finish a long rest."},{"name":"Sentry Turret","text":"You learn how to craft small sentry turrets shaped like globes that can adhere to any surface. As an action or bonus action (your choice), you can throw a sentry to a point you can see within range (30 feet + your Strength modifier x 5). At the end of each of your turns, a deployed sentry automatically targets a hostile creature within 10 feet of it. If multiple targets are available, one is chosen at random. The target must make a Dexterity saving throw. On a failed save, it takes 1d4 energy damage and gains 1 slowed level until the end of your next turn. If a creature would be targeted by more than one of these sentries, it only makes this saving throw once, taking an additional d4 damage for each sentry beyond the first.\n\nThe sentries have 1 hit point, an armor class of 10, and can be repaired over the course of a long rest. Each sentry lasts for 1 minute before deactivating. You can maintain a number of sentries equal to your Intelligence modifier. Once a sentry has been activated, it can't be activated again until you finish a short or long rest."},{"name":"Shocking Hook","text":"After hitting a creature with your grappling hook, you can use the connection to deliver an at-will tech power. As a bonus action, you can cast an at-will tech power at the target with a range of touch. If the power requires an attack roll, you have advantage. If the target requires a saving throw, the target has disadvantage.\n\nOnce you've used this feature, you can't use it again until you recover the hook.","prerequisite":"9th level, Wrist-Mounted Grappling Hook"},{"name":"Stealth Field Generator","text":"You create an augmented belt that functions as a portable, personal cloaking device. Activating or deactivating the generator requires a bonus action and, while active, you have advantage on Dexterity (Stealth) ability checks that rely on sight. The generator lasts for 1 minute. This effect ends early if you make an attack or cast a force- or tech- power.\n\nOnce the belt has been activated, it can't be activated again until you finish a short or long rest.","prerequisite":"9th level"},{"name":"Shocking Barrier","text":"You enhanced your barriers. Whenever a creature with one of your barriers active takes damage from a creature within 5 feet of it, the damaged creature can roll your Potent Aptitude die, dealing the result of the die as lightning damage to the creature that damaged it.","prerequisite":"5th level"},{"name":"Truesight Goggles","text":"You modify your goggles with a toggle allowing you to briefly gain enhanced sight. As a bonus action, you can activate the truesight feature of your goggles. When toggled on, for the next minute your goggles now automatically dispel illusions and can detect invisibility, as with truesight.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"11th level, Darkvision Goggles"},{"name":"Weapon Integration","text":"You can integrate a single weapon that weighs no more than 8 lb. into your gadgeteer harness. While integrated, that weapon gains the hidden and fixed properties."},{"name":"Withercasting Inhibitor","text":"You gain a +1 bonus to the tech save DC of powers you cast that requires a Wisdom or Charisma saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Wrist-Mounted Grappling Hook","text":"You craft a wrist-mounted grappling hook weapon attached to a tightly coiled cord. With this contraption, you can make a ranged weapon attack with a range of 30/60. On a hit, it deals 1d4 kinetic damage. This attack can target a surface, object, or creature.\n\nA creature struck by this attack is impaled by the hook. As an action, a creature can attempt to remove the hook. Removing the hook requires a Strength check. While the hook is stuck in the target, you are connected to the target by a 60 foot cable.\n\nWhile the hook is deployed, you can use your bonus action to activate the reel, pulling yourself to the location if the target is your size or larger. A creature or object smaller than you is pulled to you. Alternatively, you can opt to release the cable (no action required).\n\nOnce you've used this feature, you can't use it again until you recover and reinsert the hook as an action."}];

export const ARTIFICER_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Additonal Beam Port","text":"You install a second beam port into your modified lightsaber. Your modified lightsaber gains the double (1d8) property. You can only benefit from this property while wielding your modified lightsaber with two hands."},{"name":"Adegan Crystal","text":"You gain a +1 bonus to damage rolls made with this weapon. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Advanced Blastsaber","text":"You further fine tune your blastsaber. As an action, you can disable a single electronic device not being worn or held by another creature within 5 feet of you. The device is then disabled until it is rebooted.\n\nAdditionally, when you activate this conversion to alter the properties of your lightweapon, you create a projected barrier of ion energy in a 10-foot-radius sphere around you until the start of your next turn. Hostile creatures treat this area as difficult terrain. When a hostile creature enters the shielded area or starts its turn there, that creature takes 3d4 ion damage. Any electronics not being worn or held within the barrier's radius are disabled until rebooted.","prerequisite":"15th level, Prototype Blastsaber"},{"name":"Advanced Brightsaber","text":"You further fine tune your brightsaber. While activated, your modified lightsaber's bright light now automatically dispels illusions and can detect invisibility, as with truesight.\n\nAdditionally, when you activate this conversion to alter the properties of your lightweapon and use a bonus action to attempt to blind your target, it makes the saving throw with disadvantage.","prerequisite":"15th level, Prototype Brightsaber"},{"name":"Advanced Disruptorsaber","text":"You further fine tune your disruptorsaber. While activated, your modified lightsaber lightly obscures the area within 5 feet of it.\n\nAdditionally, when you activate this conversion to alter the properties of your lightweapon and use a bonus action to attempt to knock your target prone, the next saving throw you make before the end of your next turn has advantage.","prerequisite":"15th level, Prototype Disruptorsaber"},{"name":"Barrier","text":"On your turn, when you make an attack roll with your modified lightsaber, you can choose to forgo your proficiency bonus. If you do, you can use your reaction to erect a temporary barrier that lasts until the start of your next turn. While the barrier is activated, you have a bonus to AC against the first attack roll made against you equal to your proficiency bonus.","prerequisite":"5th level"},{"name":"Beam Gem Lens","text":"You gain a +1 bonus to attack rolls made with this weapon. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Biometric Safety Measures","text":"A security system is installed into the hilt of your lightweapon. When a creature other than you attempts to activate your lightweapon, the activation fails. Additionally, the creature attempting to activate must make on a Constitution saving throw or take lightning damage equal to engineer level, and become shocked until the start of its next turn. On a successful save the creature takes half damage and is not shocked. Regardless of success or failure, the creature drops your modified lightsaber."},{"name":"Blastsaber Conversion","text":"Incompatible with other conversions. You heavily modify your lightweapon to allow you to make a ranged weapon attack. With this modification, you can make a ranged weapon attack with a range of 30/60. On a hit, it deals 1d6 energy damage.\n\nAdditionally, when you make your first attack on your turn, you can alter the properties of your modified lightsaber. Until the start of your next turn, the damage type of your modified lightsaber is changed to ion.\n\nYou can use this trait a number of times equal to your Intelligence modifier (a minimum of once). You regain all expended uses when you complete a short or long rest."},{"name":"Brightsaber Conversion","text":"Incompatible with other conversions. You modify your lightweapon, giving it a brighter glow. While activated, your modified lightsaber sheds bright light in a 20-foot radius and dim light for an additional 20 feet.\n\nAdditionally, when you make your first attack on your turn, you can alter the properties of your modified lightsaber. Until the start of your next turn, the damage type of your modified lightsaber is changed to fire.\n\nYou can use this trait a number of times equal to your Intelligence modifier (a minimum of once). You regain all expended uses when you complete a short or long rest."},{"name":"Burn Through","text":"When you score a critical hit with your modified lightsaber, you have advantage on the next attack roll you make against that creature."},{"name":"Comfortable Handle","text":"You make minor modifications to the ergonomics of your modified saber's hilt. Your modified lightsaber gains the finesse property."},{"name":"Crossguard","text":"You add an energy guard at the base of your modified lightsaber's blade. While wielding your modified lightsaber, you gain a +1 bonus to your armor class against melee weapon attacks."},{"name":"Disruptorsaber Conversion","text":"Incompatible with other conversions. You modify your lightweapon, causing it to eminate a sickly green light. Your modified lightsaber loses the luminous property.\n\nAdditionally, when you make your first attack on your turn, you can alter the properties of your modified lightsaber. Until the start of your next turn, the damage type of your modified lightsaber is changed to acid.\n\nYou can use this trait a number of times equal to your Intelligence modifier (a minimum of once). You regain all expended uses when you complete a short or long rest."},{"name":"Extended Beam","text":"You install a series of beam focusing amplifiers into your modified lightsaber. Your modified lightsaber gains the reach property."},{"name":"Greatsaber Array","text":"You augment the configuration of your modified lightsaber. Your modified lightsaber gains the two-handed property, and it's damage die increases to 1d12."},{"name":"Intense Beam","text":"Your modified lightsaber's critical hit range increases by 1.","prerequisite":"11th level, Burn Through"},{"name":"Magnetic-Lock Grip","text":"You insert a series of magnetically charged grips into your modified lightsaber's hilt. While wielding your modified lightsaber, you have advantage on ability checks and saving throws made to disarm or avoid being disarmed."},{"name":"Prototype Blastsaber","text":"You fine tune your blastsaber. When you activate this conversion to alter the properties of your lightweapon, you can use your bonus action to cause your modified lightsaber to let loose a burst of energy. Creatures other than yourself within 5 feet of the target creature must succeed on a Dexterity saving throw. On a failed save, they take ion damage equal to your Intelligence modifier.","prerequisite":"7th level, Blastsaber Conversion"},{"name":"Prototype Brightsaber","text":"You fine tune your brightsaber. When you activate this conversion to alter the properties of your lightweapon, you can use your bonus action to attempt to blind the target of the attack. The creature must succeed on a Constitution saving throw or be blinded.","prerequisite":"7th level, Brightsaber Conversion"},{"name":"Prototype Disruptorsaber","text":"You fine tune your disruptorsaber. When you activate this conversion to alter the properties of your lightweapon, you can use your bonus action to attempt to knock the target of your attack prone. The creature must make a Strength saving throw or be knocked prone.","prerequisite":"7th level, Disruptorsaber Conversion"},{"name":"Returning Weapon","text":"You install a retractible chain in the hilt of your modified lightsaber. Your modified lightsaber gains the thrown property with a range of 20/60, and when you throw the weapon, it immediately returns to your hand."}];

export const ASTROTECH_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"AI Amplifier","text":"You gain a +1 bonus to melee tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"AI Rangefinder","text":"You gain a +1 bonus to ranged tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Advanced Hardening","text":"You have resistance to ion damage.","prerequisite":"15th level, Hardening"},{"name":"Advanced Grounding System","text":"You have resistance to lightning damage.","prerequisite":"15th level, Prototype Grounding System"},{"name":"Advanced Jamming Phased Array","text":"While your jamming field is active, any hostile creature within the field must make a Constitution saving throw at the end of each of its turns to maintain concentration on the power.","prerequisite":"15th level, Prototype Jamming Phased Array"},{"name":"Advanced Ionizing Phased Array","text":"While your ionizing field is active, your tech powers and class features ignore resistance to ion damage, and immunity to ion damage is instead treated as resistance from any creature within range of your field.\n\nAdditionally, when you use your Ionizing Phased Array feature, you create a fourth blast.","prerequisite":"15th level, Prototype Pulsating Phased Array"},{"name":"Advanced Targeting Phased Array","text":"While your targeting field is active, as an action, you can allow a number of allies within the field up to your Intelligence modifier (minimum of one) to use their reaction to make a ranged weapon attack against a single target you can see.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"15th level, Prototype Targeting Phased Array"},{"name":"Droid Restraints","text":"When you would install a restraining bolt, you can do so in half the time. Additionally, when determining the save DC of a restraining bolt you control, you can use your tech save DC, if it would be higher than the item's DC."},{"name":"Flashlight Attachment","text":"You affix a targeted light to your electronic warfare platform. As a bonus action, you can toggle the light on or off. While on, your electronic warfare platform sheds bright light in a 60-foot cone."},{"name":"Fadecasting Controller","text":"You gain a +1 bonus to the tech save DC of powers you cast that requires a Strength or Constitution saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Grounding System","text":"You have advantage on saving throws against lightning damage."},{"name":"Hacked Communications","text":"As a bonus action, you may choose any number of creatures that you can see within 60 feet of you that have commlinks, headcomms, or other such communications devices. Each creature must succeed on a Constitution saving throw or take sonic damage equal to your Intelligence modifier (minimum of one). Additionally, on a failed save, their communication devices are disabled until rebooted.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again."},{"name":"Hardening","text":"You have advantage on saving throws against ion damage."},{"name":"Intelligence Core Override","text":"You can cast the *override interface* tech power at 5th level without spending tech points.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"9th level"},{"name":"Ionizing Phased Array","text":"While your ionizing field is active, as an action, you can send forth blasts of directed ionic energy. Make two ranged tech attacks against targets within the field. These attacks can target the same creature or different ones. Make separate attack rolls for each blast. The attack deals 1d6 ion damage on a hit.","prerequisite":"5th level"},{"name":"Jamming Phased Array","text":"While your jamming field is active, as an action, you can choose a number of creatures concentrating on a power equal to your Intelligence modifier (a minimum of one) within your field, and force them to make a Concentration saving throw. If you cause at least one creature to lose concentration on a power using this feature, you can use your reaction to make all creatures that lost concentration take ion damage equal to your Intelligence modifier."},{"name":"Miniaturized Repulsor Coils","text":"Your electronic warfare platform can store 20 lb., not exceeding 1 cubic foot, which does not count towards your encumbrance."},{"name":"Prototype Transmitter","text":"You further tweak your transmitter design, extending the area of your fields. When you activate a field you may choose to double the radius of your field.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"7th level"},{"name":"Prototype Grounding System","text":"You have immunity to the shocked condition.","prerequisite":"7th level, Grounding System"},{"name":"Prototype Jamming Phased Array","text":"While your jamming field is active, when a creature within your field attempts to cast a tech power, you can use your reaction to cast the *tech override* power at 3rd level without spending tech points. When you cast this power using this feature and you make the techcasting ability check as a part of this casting, you add your proficiency bonus to the check.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"7th level, Jamming Phased Array"},{"name":"Prototype Ionizing Phased Array","text":"While your ionizing field is active, when you cast a tech power or use a class feature that affects other creatures within the radius of your field, you can choose a number of them equal to 1 + the power's level. The chosen creatures automatically succeed on their saving throws against the power, and they take no damage if they would normally take half damage on a successful save.\n\nAdditionally, when you use your Ionizing Phased Array feature, you create a third blast.","prerequisite":"7th level, Ionizing Phased Array"},{"name":"Prototype Targeting Phased Array","text":"While your targeting field is active, as an action, you can cast the *scramble interface* power at 3rd level without spending tech points.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"7th level, Target Marking Phased Array"},{"name":"Redundant Circuits","text":"You can have two fields active at a time.","prerequisite":"15th level"},{"name":"Rendcasting Controller","text":"You gain a +1 bonus to the tech save DC of powers you cast that requires a Dexterity or Intelligence saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Sensor Scramblers","text":"All creatures within 10 feet of you become undetectable to electronic sensors and cameras for the next 10 minutes. Anything these creatures are wearing or carrying is also undetectable, so long as it's on the creature's person. The creatures are still visible to regular vision.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"5th level"},{"name":"Stealth Field Generator","text":"You integrate a portable, personal cloaking device into your electronic warfare platform. Activating or deactivating the generator requires a bonus action and, while active, you have advantage on Dexterity (Stealth) ability checks that rely on sight. The generator lasts for 1 minute. This effect ends early if you make an attack or cast a force or tech power.\n\nOnce the generator has been activated, it can't be activated again until you finish a short or long rest.","prerequisite":"7th level"},{"name":"Targeting Phased Array","text":"While your targeting field is active, as an action, you can choose a number of creatures equal to your Intelligence modifier you can see within 60 feet (a minimum of one creature), and force them to make a Dexterity saving throw. On a failed save, all ranged weapon attacks made by allies within your field against the target have advantage until the beginning of your next turn.","prerequisite":"5th level"},{"name":"Truelight Attachment","text":"You modify your electronic warfare platform with a toggle allowing you to briefly gain enhanced sight. As a bonus action, you can activate the truesight feature of your electronic warfare platform. When toggled on, for the next minute your electronic warfare platform now automatically dispel illusions and can detect invisibility, as with truesight.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"11th level, Flashlight Attachment"},{"name":"Withercasting Controller","text":"You gain a +1 bonus to the tech save DC of powers you cast that requires a Wisdom or Charisma saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"X-Ray Targeting","text":"You tweak your sensors to find weak points in thick armor. Your weapon attacks and tech powers deal double damage against constructs.","prerequisite":"5th level"}];

export const AUDIOTECH_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Advanced Battle Enhancement","text":"While playing your Song of Battle, your tech powers and class features ignore resistance to sonic damage, and immunity to sonic damage is instead treated as resistance from any creature within range of your song that can hear you.\n\nAdditionally, when you use your Battle Song Enhancement feature, you create a fourth burst.","prerequisite":"15th level, Prototype Battle Enhancement"},{"name":"Advanced Disruption Enhancement","text":"While playing your Song of Disruption, any hostile creature within range of your song that can hear you must make a Constitution saving throw at the end of each of its turns to maintain concentration on the power.","prerequisite":"15th level, Prototype Disruption Enhancement"},{"name":"Advanced Support Enhancement","text":"While playing your Song of Support, allies add your Intelligence modifier to their death saving throws (minimum of +1). If this amount would increase the roll of the d20 to 20 or greater, the creature regains 1 hit point.","prerequisite":"15th level, Prototype Support Enhancement"},{"name":"Battle Song Enhancement","text":"While playing your Song of Battle, as an action, you can send forth busts of directed sonic energy, make two ranged power attacks. These attacks can target the same creature different ones. Make separate attack rolls for each burst. The attack has a range equal to the radius of your song, and deals 1d8 sonic damage on a hit.","prerequisite":"5th level"},{"name":"Disruption Song Enhancement","text":"While playing your Song of Disruption, as an action, you can choose a number of creatures concentrating on a power equal to your Intelligence modifier (a minimum of one) within range of your song that can hear you, and force them to make a Concentration saving throw. If you cause at least one creature to lose concentration on a power using this feature, you can use your reaction to make all creatures that lost concentration take damage equal to your Intelligence modifier.","prerequisite":"5th level"},{"name":"Enthralling Performance","text":"For the duration of an enhanced song you play, whenever any creature that can hear your song tries to attack you for the first time on a turn, the attacker must make a Charisma saving throw. On a failed save, it can't attack you on this turn, and it must choose a new target for its attack or the attack is wasted. On a successful save, it can attack you on this turn, but it has disadvantage on any saving throw it makes against your powers or features on your next turn.\n\nOnce you've used this feature, you must complete a long rest before you can use it again.","prerequisite":"13th level, Hypnotic Melody"},{"name":"Finding My Way","text":"While you are playing an enhanced song, when a creature would make a melee attack roll against you, you can use your reaction to move 5 feet without provoking opportunity attacks, imposing disadvantage on the roll.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest.","prerequisite":"Rush"},{"name":"Hypnotic Melody","text":"As an action while wielding your modified instrument, you can begin to play a song woven with subtle hypnotic influence. Choose a number of creature up to your Intelligence modifier. If those creatures listen to this song for a full minute, they must succeed on a Wisdom saving throw or become charmed by you for 1 minute. Creatures that succeed the saving throw are not aware that you attempted to influence them, nor are creatures that failed their saving throw once the power ends.\n\nOnce you've used this feature, you can't use it again until you finish a short or long rest."},{"name":"Inaudible Casting","text":"When you cast a tech power or make use of a feature that requires playing your modified instrument, you can choose to do so quietly. Creatures have disadvantage on Intelligence (Investigation) and Wisdom (Perception) checks that rely on sound to determine you cast a tech power.","prerequisite":"7th level, Simple Melodies"},{"name":"Long Range Noise","text":"The radius of your songs increases to 120 feet. Additionally, any tech power you cast with your modified instrument that deals sonic damage and has a range of 10 feet or greater gains a range of 120 feet.","prerequisite":"13th level"},{"name":"Magnifying Device","text":"While using your instrument as a tech focus, you gain a +1 bonus to tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Overwhelming Soundwaves","text":"While playing, creatures of your choice treat a 15-foot-radius sphere around you as difficult terrain. Additionally, as an action, you can cause each affected creature to make a Constitution saving throw, taking 3d8 sonic damage on a failed save.","prerequisite":"15th level"},{"name":"Prototype Battle Enhancement","text":"While playing your Song of Battle, when you cast a tech power or use a class feature that affects other creatures within the radius of your song, you can choose a number of them equal to 1 + the power's level. The chosen creatures automatically succeed on their saving throws against the power, and they take no damage if they would normally take half damage on a successful save.\n\nAdditionally, when you use your Battle Song Enhancement feature, you create a third burst.","prerequisite":"9th level, Battle Song Enhancement"},{"name":"Prototype Disruption Enhancement","text":"While playing your Song of Disruption, when a creature you can see that can hear you attempts to cast a power, you can use your reaction to cast the *tech override* power at 3rd level. When you cast this power using this feature, the power works against both tech and force powers, and when you make the techcasting ability check as a part of this casting, you add your proficiency bonus to the check.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"9th level, Disruption Song Enhancement"},{"name":"Prototype Support Enhancement","text":"While playing your Song of Support, when you use your Song of Support's Potent Amplitude feature, the target instead takes no damage if they succeed on the saving throw, and only half damage if they fail.","prerequisite":"9th level, Support Song Enhancement"},{"name":"Restful Melody","text":"Over the course of a short rest, you can play a rejuvenating song to assist in the recovery of your allies. If you or any friendly creatures who can hear your performance regain hit points at the end of the short rest, each of those creatures regains an extra 1d6 hit points.\n\nThe extra hit points increase when you reach certain levels in this class: to 1d8 at 9th level, to 1d10 at 13th level, and to 1d12 at 17th level."},{"name":"Rush","text":"While you are playing an enhanced song, your speed increases by 10 feet, and opportunity attacks made against you have disadvantage."},{"name":"Sharp Noise","text":"As an action while wielding your modified instrument, choose a creature you can see. If it can hear you, it must succeed on a Constitution saving throw or take 1d4 sonic damage and have disadvantage on its next attack roll before the end of its next turn.\n\nThis feature's damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4)."},{"name":"Shock Mount","text":"While using your instrument as a tech focus, you gain a +1 bonus to your tech save DC. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Simple Melodies","text":"When you are holding your modified instrument, and not actively playing a song, any tech power that you could cast that could have its damage type altered by your Potent Amplitude feature can be cast as if used with Potent Amplitude.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."},{"name":"Sonar Pulse","text":"As an action while wielding your modified instrument, you can release a wave of sound that provides feedback on your surroundings. For the next minute, you have advantage on Wisdom (Perception) and Intelligence (Investigation) checks to search for hidden doors, traps, or invisible creatures.\n\nOnce you've used this feature, you can't use it again until you finish a short or long rest."},{"name":"Song Flow","text":"While playing an enhanced song, you can use your bonus action to change from one song to another.","prerequisite":"11th level"},{"name":"Support Song Enhancement","text":"While playing your Song of Support, when you cast a tech power that restores hit points or grants temporary hit points, the amount restored or granted is increased by an amount equal to your Intelligence modifier (minimum of +1).","prerequisite":"5th level"},{"name":"Weapon Integration","text":"You can integrate a single weapon that weighs no more than 8 lb. into your instrument. While integrated, that weapon gains the hidden property."}];

export const BIOCHEM_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Biochemist's Amplifer","text":"While using your biochemist's pack as a tech focus, you gain a +1 bonus to tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Biochemist's Inhibitor","text":"While using your biochemist's pack as a tech focus, you gain a +1 bonus to your tech save DC. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Chemical Counteragents","text":"You may choose one type of damage that benefits from your Biochemist's Touch and Potent Mixtures features. While wearing your modified biochemist's pack you have resistance to that type of damage.\n\nYou can select this modification multiple times. Each time you do so, you must choose a different damage type."},{"name":"Countertoxin","text":"When you or an ally within 30 feet of you is suffering from the poisoned condition, you may use your reaction on your turn to end the poisoned condition on that creature. The creature also gains immunity to the poisoned condition for one minute.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."},{"name":"Detachable Distribution System","text":"You upgrade your distributor with a secondary, detachable distributor. As a bonus action, you can throw your detachable distributor at a point within range. Your detachable distributor has a range equal to 30 feet + your Strength modifier x 5. Your detachable distributor works for 1 minute before coming inert. Once it does so, you can't use it again until you recover it as an action.\n\nAdditionally, while your detachable distributor is within 100 feet of you, when you use your action to activate your distributor, you can choose to affect each creature within 5 feet of your detachable distributor. You can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."},{"name":"Drone Distribution System","text":"You upgrade your distributor, interfacing it with the target of your *tracker droid interface* power. When you use your action to activate your distributor, while your tracker droid is within 100 feet of you, you can choose to have your tracker droid deliver the mixture. Your tracker droid must use its reaction to deliver the mixture.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."},{"name":"Expanded Chemicals: Combustibles","text":"You add additional chemicals to your modified biochemist's pack. When you deal fire damage with a tech power or class feature, you can use your Biochemist's Touch and Potent Mixture features.\n\nAdditionally, when a creature fails their Dexterity saving throw against your Corrosive Mixtures feature, you can choose to instead deal fire damage. If you do so, each creature within 5 feet of the target takes fire damage equal to your Intelligence modifier. You can use this feature three times. You gain an additional use at 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest.","prerequisite":"5th level"},{"name":"Expanded Chemicals: Cryogenics","text":"You add additional chemicals to your modified biochemist's pack. When you deal cold damage with a tech power or class feature, you can use your Biochemist's Touch and Potent Mixture features.\n\nAdditionally, when a creature fails their Constitution saving throw against your Noxious Mixtures feature, you can choose to instead deal cold damage. If you do so, it gains 1 slowed level until the start of your next turn. You can use this feature three times. You gain an additional use at 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest.","prerequisite":"5th level"},{"name":"Expanded Chemicals: Restorative","text":"You add additional chemicals to your modified biochemist's pack. When you restore hit points with a tech power or class feature, you can use your Biochemist's Touch and Potent Mixture features.\n\nAdditionally, when you use your Invigorating Mixture to grant temporary hit points to a creature, you can choose to restore that many hit points to the same creature. You can use this feature three times. You gain an additional use at 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest.","prerequisite":"5th level"},{"name":"Expanded Mixtures: Adhesive","text":"You've created a new mixture from your chemicals that you can use when you activate your distributor. When you do so, the target creature must make a Strength saving throw. If the creature is Large or larger, it has advantage on the saving throw. On a failed save, a creature gains 4 slowed levels until the start of your next turn. As an action on their turn, an affected creature can repeat this saving throw, ending the effect on a success."},{"name":"Expanded Mixtures: Blinding","text":"You've created a new mixture from your chemicals that you can use when you activate your distributor. When you do so, the target creature must make a Constitution saving throw. On a failed save, a creature is blinded until the start of your next turn."},{"name":"Expanded Mixtures: Hallucinogenic","text":"You've created a new mixture from your chemicals that you can use when you activate your distributor. When you do so, the target creature must make an Intelligence saving throw. On a failed save, the target loses the ability to distinguish friend from foe, regarding all creatures it can see as enemies until the end of your next turn. Each time the target takes damage, it can repeat the saving throw, ending the effect on itself on a success.\n\nWhenever the affected creature chooses another creature as a target, it must choose the target at random from among the creatures it can see within range of the attack, power, or other ability it's using. If an enemy provokes an opportunity attack from the affected creature, the creature must make that attack if it is able to.\n\nThis feature has no effect on droids or constructs."},{"name":"Explosive Distribution System","text":"You upgrade your distributor, granting it the ability to create a volley. When you use your action to activate your distributor, you can choose to affect each creature in a 10-foot-radius sphere centered on a point you can see within 30 feet.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."},{"name":"Injection Apparatus","text":"You install a wrist mounted injection apparatus into your modified biochemist's pack. It is a simple vibroweapon with the finesse and light properties, and deals 1d4 kinetic damage on a hit. Your injection apparatus does not fill the hand slot, but you can't use it while the hand is full.\n\nWhen you hit with the weapon, you can activate your distributor to deploy one of your mixtures. If you do so, the target has disadvantage on the saving throw against your mixture."},{"name":"Inoculation","text":"You gain immunity to the poisoned and disease conditions."},{"name":"Integrated EVA Functionality","text":"You make several additions to your modified biochemist's pack, you are protected from hazardous conditions, as if wearing an EVA suit, for as long as you are wearing your modified biochemist's pack."},{"name":"Kolto Aerosol","text":"You add a special dispersal system to your modified biochemist's pack. This system slowly disperses small amounts of kolto in the air. If creatures spend the entirety of a long rest within 30 feet of you, they regain all expended Hit Dice, instead of only half. Additionally, they are cured of any poisons or diseases that are suffering from.","prerequisite":"9th level"},{"name":"Long-Range Distribution System","text":"You upgrade your distributor, improving the range. When you use your action to activate your distributor, you can choose to increase the range to 60 feet.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."},{"name":"Luminous Gel","text":"You've added a light-emitting gel to your modified biochemist's pack. As an action, you can coat an item, object, or location up to 5-foot-square with this gel. When you do so, the gel sheds bright light in a 10-foot radius and dim light for an additional 10 feet. The gel lasts for 1 hour before losing its potency. You can end this effect as a bonus action."},{"name":"Oil Spill","text":"As an action, you can cast the *oil slick* tech power without expending tech points. Casting the power in this way does not require concentration, and the oil will remain in place for the full duration of the power.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again."},{"name":"Persistent Chemicals","text":"Whenever you use your Biochemist's Touch feature, you may select one creature that was damaged. At the start of each of that creature's turns, it must make a Constitution saving throw. On a failed save, it takes damage of the triggering type equal to your Intelligence modifier and has disadvantage on attack rolls until the start of its next turn. On a success, this feature ends, and the creature becomes immune to it for one day.\n\nOnce you've used this feature, you must complete a short or long rest before you can use it again.","prerequisite":"7th level"},{"name":"Piercing Gel","text":"Your luminous gel now automatically dispels illusions and can detect invisibility, as with truesight.","prerequisite":"11th level, Luminous Gel"},{"name":"Self-Injection Module","text":"You install a special kolto injector into your modified biochemist's pack that can inject you with kolto in response to pain. When you take damage, you can use your reaction and expend a Hit Die to regain health as long as the damage would not reduce your hit points to 0."},{"name":"Smart Dispersal System","text":"When you activate your distributor, you can choose a number of creature equal to your Intelligence modifier. Those creature automatically succeed on their saving throws against your mixtures."},{"name":"Spray Distribution System","text":"You upgrade your distributor, granting it the ability to spray in a cone. When you use your action to activate your distributor, you can choose to affect each creature in a 15-foot cone.\n\nYou can use this feature twice. You gain an additional use at 5th, 9th, 13th, and 17th level. You regain all expended uses when you complete a short or long rest."}];

export const BIOTECH_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Active Camouflage Core","text":"As an action, you can activate this augmentation to cast the *infiltrate* tech power targeting yourself. Intelligence is your tech casting ability for this power, and if you cast it using this augmentation, it does not require concentration.","prerequisite":"13th level"},{"name":"Anti-Dazzle Ocular Implant","text":"This augmentation replaces your eyes.\n\nYou are immune to the blinded condition, and you can enable or disable your ability to see anytime. Additionally, your eyes are equipped with a holorecorder device. You can perfectly recall anything you've seen in the last 7 days."},{"name":"Auto-Defibrillator","text":"The Constitution score of your Hardy Torso Prosthesis increases by 2. Additionally, when you are reduced to 0 hit points but not killed outright, you can drop to 1 hit point instead. You can't use this feature again until you finish a long rest.","prerequisite":"5th level, Hardy Torso Prothesis"},{"name":"Brawny Arm Prosthesis","text":"This augmentation replaces an arm.\n\nWhen you make an ability check, attack roll, or saving throw using Strength using only this arm, your Strength score is treated as 15. When you make an ability check, attack roll, or saving throw using Strength using more than just this arm, you take the average of the arm's Strength score and your own.\n\nYou can choose this modification multiple times."},{"name":"Celerity Leg Prosthesis","text":"This augmentation replaces both legs.\n\nWhen determining your bonus to AC and saving throws from Dexterity, your Dexterity score is treated as 15. If your Dexterity score is already equal to or greater than 15, it has no effect on you.\n\nAdditionally, you can substitute this score for your own whenever you make an ability check or attack roll that uses your legs."},{"name":"Detachable Eye","text":"This augmentation replaces an eye.\n\nAs an action, you can remove or replace this eye. While removed, the eye sprouts eight small legs, has a speed of 15 feet, an AC of 10, and 1 hit point. If it dies, you can't use it again until you complete a long rest. As an action on each of your turns, you can move the eye up to its speed as long as it is within 30 feet of you. You can see through both the detached eye and your remaining eye at the same time, or you can use your action to see through only one eye or the other.\n\nYou can choose this modification multiple times."},{"name":"Detachable Hand","text":"This augmentation replaces a hand.\n\nAs an action, you can attach or detach this hand. While detached, the hand has a speed of 15 feet, an AC of 10, and 1 hit point. If it dies, you can't use it again until you complete a long rest. As an action on each of your turns, you can control the hand as long as it is within 30 feet of you. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a container. You can move the hand up to its speed each time you use it.\n\nYou can choose this modification multiple times."},{"name":"Fadecasting Inhibitor","text":"While using your body as a tech focus, you gain a +1 bonus to the tech save DC of powers you cast that requires a Strength or Constitution saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Hardy Torso Prosthesis","text":"This augmentation replaces your torso.\n\nYour Constitution score becomes 13. Additionally, you have advantage on saving throws against poison."},{"name":"Harpoon Hand","text":"This augmentation replaces a hand.\n\nYou modify your hand, granting it the ability to transform into a harpoon. With this hand, you can make a ranged weapon attack with a range of 30/60. On a hit, it deals 1d6 kinetic damage. This attack can target a surface, object, or creature.\n\nA creature struck by this attack is impaled by the harpoon. As an action, a creature can attempt to remove the harpoon. Removing the harpoon requires a Strength check. While the harpoon is stuck in the target, you are connected to the target by a 60 foot cable.\n\nWhile the harpoon is deployed, you can use your bonus action to activate the reel, pulling yourself to the location if the target is larger than you. A creature or object your size or smaller is pulled to you. Alternatively, you can opt to release the cable (no action required).\n\nOnce you've used this feature, you can't use your hand again until you recover and reinsert it as an action.\n\nYou can choose this modification multiple times."},{"name":"Integrated Subdermal Armor","text":"When you aren't wearing armor, your AC becomes 13 + your Dexterity modifier.","prerequisite":"5th level"},{"name":"Iridonian Grav-lev Hand","text":"This augmentation replaces a hand.\n\nYour unarmed strikes with this arm deal 1d4 ion damage, and your carrying capacity and the weight you can push, drag, or lift doubles. Additionally, you deal double damage to energy-based structures with your unarmed strikes.\n\nYou can choose this modification multiple times."},{"name":"Magnetic Forearm Enhancement","text":"This augmentation replaces a forearm.\n\nUnarmed strikes with this hand have the reach property.\n\nYou can choose this modification multiple times."},{"name":"Mighty Prowess Enabler","text":"The Strength score of your Brawny Arm Prosthesis increases by 2. Additionally, you are considered proficient with any weapon you wield with this arm. If the weapon requires two hands to use, and you are not already proficient with it, you only add half your proficiency bonus to attack rolls you make with it, unless you wield it with two of these arms.\n\nYou can choose this modification multiple times, but only once per arm.","prerequisite":"5th level, Brawny Arm Prothesis"},{"name":"Nighthawk Ocular Implant","text":"This augmentation replaces your eyes.\n\nYou can activate or deactivate this implant as a bonus action. While active, you gain darkvision to a range of 120 feet."},{"name":"Powered Harpoon Hand","text":"While your harpoon hand is deployed, when you cast a tech power with a range of touch, your hand can deliver the power as if it had cast it.","prerequisite":"9th level, Harpoon Hand"},{"name":"Rendcasting Inhibitor","text":"While using your body as a tech focus, you gain a +1 bonus to the tech save DC of powers you cast that requires a Dexterity or Intelligence saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Skills Enhancement Package","text":"When you make an ability check using a skill you are proficient in, you can roll a d4 and add the result to your total.","prerequisite":"13th level"},{"name":"Sound Dampeners","text":"This augmentation replaces your ears.\n\nYou are immune to the deafened condition, and you can enable or disable your ability to hear anytime. Additionally, your ears are equipped with a personal translator that allows you to understand up to 15 different languages, however, you cannot speak them. The languages can be changed out while interfaced with a protocol droid or appropriate computer."},{"name":"Surveillance Implant","text":"This augmentation replaces your face.\n\nThis implant includes a headcomm with a scrambler that automatically encodes messages sent to a specified recipient commlink or receiver."},{"name":"Survival and Surveillance Implant","text":"This augmentation replaces your eyes and face.\n\nThis implant contains several tools for long-term survival and reconnaissance. As a bonus action, you can activate one of the below modes that enable you to use several of these tools at once. Activating a different mode deactivates any currently active mode.\n\nCommunications Mode: This communications suite includes a headcomm with a scrambler that automatically encodes messages sent to a specified recipient commlink or receiver. While this mode is active, you cannot be deafened.\n\nInterceptor Mode: This is a jamming and electronic warfare suite that includes a comm jammer, a holotrace device and pocket scrambler.\n\nRespirator Mode: This includes a basic respirator that grants advantage on saving throws made to avoid being poisoned and resistance to poison damage.","prerequisite":"9th level"},{"name":"Swift Gait Attuner","text":"The Dexterity score of your Celerity Leg Prosthesis increases by 2. Additionally, you gain proficiency in Dexterity saving throws.","prerequisite":"5th level, Celerity Leg Prothesis"},{"name":"Vector Amplifier","text":"While using your body as a tech focus, you gain a +1 bonus to melee tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Vector Rangefinder","text":"While using your body as a tech focus, you gain a +1 bonus to ranged tech attack rolls. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Voice Synthesizer","text":"This augmentation replaces your throat.\n\nThis augmentation allows you to synthesize and perfectly mimic any voice that you have heard in the last month, and the synthesizer can translate verbal communications between up to 5 languages. The languages can be changed out while interfaced with a protocol droid or appropriate computer. Additionally, you can add your Intelligence modifier to any Charisma (Deception) check made to lie to another creature.","prerequisite":"5th level"},{"name":"Weapon Integration","text":"This augmentation replaces a forearm.\n\nYou can integrate a single weapon that weighs no more than 8 lb. into your forearm. While integrated, you can use a bonus action to hide or reveal the weapon, which can only be used while revealed. While hidden, the weapon has the hidden property. While revealed, the weapon has the fixed property.\n\nYou can choose this modification multiple times."},{"name":"Withercasting Inhibitor","text":"While using your body as a tech focus, you gain a +1 bonus to the tech save DC of powers you cast that requires a Wisdom or Charisma saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"}];

export const CYBERTECH_MODIFICATIONS: ClassSubChoiceOption[] = [{"name":"Arakyd Vector","text":"You gain a +1 bonus to tech attack rolls. This bonus increases to +2 at 11th level and +3 at 17th level.","prerequisite":"5th level"},{"name":"Careful Subroutine","text":"When you cast a power that forces other creatures to make a saving throw, you can protect some of those creatures from the power's full force. To do so, you spend 1 additional tech point and choose a number of those creatures up to your Intelligence modifier (minimum of one). A chosen creature automatically succeeds on its saving throw against the power.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted."},{"name":"Cryo Amplifier","text":"When a creature takes cold damage from a tech power that you cast that requires an attack roll or saving throw, you deal additional cold damage equal to your Intelligence modifier (minimum of +1)."},{"name":"Cryo Amplifier, Mk II","text":"When you deal damage to a creature with this amplifier, the creature gains one level of slowed until the end of your next turn. If the tech power already imposes levels of slowed, the number of slowed levels imposed increases by 1.\n\nYou can use this feature a number of times equal to your Intelligence modifier (minimum of 1). You regain all expended uses when you complete a long rest.","prerequisite":"7th level, Cryo Amplifier"},{"name":"Cryo Amplifier, Mk III","text":"When you expend a use of your Cryo Amplifier, Mk II, when the creature fails Constitution saving throw it instead becomes restrained until the start of your next turn.","prerequisite":"13th level, Cryo Amplifier, Mk II"},{"name":"Distant Subroutine","text":"When you cast a power that has a range of 5 feet or greater, you can spend 1 additional tech point to double the range of the power.\n\nAlternatively, when you cast a power that has a range of touch, you can spend 1 additional tech point to make the range of the power 30 feet.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted."},{"name":"Electrical Amplifier","text":"When a creature takes lightning damage from a tech power that you cast that requires an attack roll or saving throw, you deal additional lightning damage equal to your Intelligence modifier (minimum of +1)."},{"name":"Electrical Amplifier, Mk II","text":"When you deal damage to a creature with this amplifier, the creature must succeed at a Constitution saving throw or become shocked until the end of your next turn.\n\nYou can use this feature a number of times equal to your Intelligence modifier (minimum of 1). You regain all expended uses when you complete a long rest.","prerequisite":"7th level, Electrical Amplifier"},{"name":"Electrical Amplifier, Mk III","text":"When you expend a use of your Electrical Amplifier, Mk II, when the creature fails Constitution saving throw it instead becomes stunned until the start of your next turn.","prerequisite":"13th level, Electrical Amplifier, Mk II"},{"name":"Extended Subroutine","text":"When you cast a power that has a duration of 1 minute or longer, you can spend 1 additional tech point to double its duration, to a maximum duration of 24 hours.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted."},{"name":"Evaluation scanner","text":"You can cast the *Analyze* power without using tech points. If you use this on a tech focus, you learn what tech powers, if any, are within it."},{"name":"Explosive Amplifier","text":"When a creature takes fire damage from a tech power that you cast that requires an attack roll or saving throw, you deal additional fire damage equal to your Intelligence modifier (rounded up, minimum of +1)."},{"name":"Explosive Amplifier, Mk II","text":"When you deal damage to a creature with this amplifier, it becomes ignited (your techcasting ability modifier) until the start of its next turn.\n\nYou can use this feature a number of times equal to your Intelligence modifier (minimum of 1). You regain all expended uses when you complete a long rest.","prerequisite":"7th level, Explosive Amplifier"},{"name":"Explosive Amplifier, Mk III","text":"When a creature is ignited with a use of your Explosive Amplifier, Mk II and that creature takes any fire damage while ignited, the creature has disadvantage on the next Dexterity saving throw it makes before the start of its next turn.","prerequisite":"13th level, Explosive Amplifier, Mk II"},{"name":"Elemental Absorbtion","text":"You can cast the *Absorb Energy* power once without expending Tech Points. You can't do so again until you finish a short or long rest."},{"name":"Elemental Ingenuity","text":"When you cast a power that deals fire, lightning, or cold damage, you can spend 1 additional tech point and choose to swap the damage type to fire, lightning, or cold damage.","prerequisite":"11th level"},{"name":"Elemental Ingenuity, Mk II","text":"When you cast a power that deals acid, ion, poison, or sonic damage, you can expend 1 additional tech point and choose to swap the damage type to fire, lightning, or cold damage.","prerequisite":"13th level, Elemental Ingenuity"},{"name":"Elemental Shielding","text":"You gain resistance to damage types for which you have a matching amplifier modification installed.","prerequisite":"11th level, Cryo Amplifier, Explosive Amplifier, or Electrical Amplifier"},{"name":"Frailcasting Dynamics","text":"While using your wristpad as a tech focus, you gain a +1 bonus to the tech save DC of powers you cast that requires a Strength or Constitution saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Hasty Translation","text":"You can cast the *Translation Program* power once without expending Tech Points. You can't do so again until you finish a short or long rest."},{"name":"Heightened Subroutine","text":"When you cast a power that forces a creature to make a saving throw to resist its effects, you can spend 2 additional tech points to give one target of the power disadvantage on its first saving throw made against the power.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted.","prerequisite":"5th level"},{"name":"Improved Subroutine","text":"When you roll damage for a power, you can spend 1 additional tech point to reroll a number of the damage dice up to your Intelligence modifier (minimum of one). You must use the new rolls.\n\nYou can use Improved Subroutine even if you have already used a different Subroutine modification during the casting of the power."},{"name":"Lingering Subroutine","text":"When you cast a power that requires concentration to maintain you can choose to spend 3 additional tech points. If you do, when you lose concentration on the power, the power will not end until the end of your next turn.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted.","prerequisite":"5th level"},{"name":"Long Range Comms","text":"You can cast the *Sending* power, targeting a creature whose frequency is in your wristpad, without using tech points. A willing creature can use its action to register its comm frequency on your device, which can contain a number of frequencies equal to your proficiency bonus.\n\nAs an action, you can remove a frequency on the device by deleting it.","prerequisite":"5th level"},{"name":"Pinpoint Subroutine","text":"When you cast a power that allows you to force creatures in an area to make a saving throw you can instead spend 1 tech point and make a ranged tech attack against a single target that would be in the range. On a hit the target suffers the effects as though they failed their saving throw.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted."},{"name":"Quickened Subroutine","text":"When you cast a power that has a casting time of 1 action, you can spend 2 additional tech points to change the casting time to 1 bonus action for this casting.\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted.","prerequisite":"5th level"},{"name":"Refocused Subroutine","text":"When you are forced to make a Constitution saving throw to maintain concentration on a power you can use your reaction and spend 2 tech points to automatically succeed on the saving throw.\n\nYou can use Refocused Subroutine even if you have already used a different Subroutine modification during the casting of the power.","prerequisite":"5th level"},{"name":"Rendcasting Dynamics","text":"While using your wristpad as a tech focus, you gain a +1 bonus to the tech save DC of powers you cast that requires a Dexterity or Intelligence saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"},{"name":"Seeking Subroutine","text":"If you miss with a tech power that calls for an attack roll, you can spend 2 tech points to reroll the attack. You must use the new roll.\n\nYou can use Seeking Subroutine even if you have already used a different Subroutine modification during the casting of the power.","prerequisite":"5th level"},{"name":"Thermodynamic Conservation","text":"Once per round when you take cold, fire, or lightning damage from a force or tech power, you gain temporary hit points equal to twice the power's level to potentially absorb the damage (minimum of 1). These points last until the end of your next turn.\n\nIf the Mk II upgrade of the affecting amplifier is installed, the temporary hit points gained increase by an amount equal to your Intelligence modifier (minimum of 1)."},{"name":"Twinned Subroutine","text":"When you cast a power that can only have one target and doesn't have a range of self, you can spend a number of additional tech points equal to the power's level to choose a second target in range with the same power (1 tech point if the power is at-will).\n\nYou can use only one Subroutine modification on a power when you cast it, unless otherwise noted.","prerequisite":"5th level"},{"name":"Voltaic Screen","text":"You can cast the *Voltaic Shielding* power once without expending Tech Points. You can't do so again until you finish a short or long rest."},{"name":"Withercasting Dynamics","text":"While using your wrist as a tech focus, you gain a +1 bonus to the tech save DC of powers you cast that requires a Wisdom or Charisma saving throw. This bonus increases to +2 at 9th level and +3 at 13th level.","prerequisite":"5th level"}];

